class HandlerRegistry:
    def __init__(self) -> None:
        self._handlers: dict[str, object] = {}

    def register(self, topic: str, handler: object) -> None:
        self._handlers[topic] = handler

    def resolve(self, topic: str) -> object:
        try:
            return self._handlers[topic]
        except KeyError:
            raise KeyError(f"no handler for {topic!r}") from None
